import React from "react";
import "./Footer.css";

function Footer() {

    return (

        <footer className="footer">

            <div className="footer__container">

                <h2>ShopEase</h2>

                <p>

                    Your one-stop destination for quality products.

                </p>

                <p>

                    © 2026 ShopEase. All Rights Reserved.

                </p>

            </div>

        </footer>

    );

}

export default Footer;
